import base64
import io
from PIL import Image
import os

LOGO_B64 = ""

QR_PATH = r"C:\Users\DELL\KCA\Kone-Code-Academy\qr_code.png"

print("Debugging...")

# 1. Try to load logo
try:
    print("Loading logo...")
    if "base64," in LOGO_B64:
        LOGO_B64_CLEAN = LOGO_B64.split("base64,")[1]
    else:
        LOGO_B64_CLEAN = LOGO_B64.strip()
    
    logo_data = base64.b64decode(LOGO_B64_CLEAN)
    print(f"Decoded data length: {len(logo_data)} bytes")
    
    with open("debug_logo.png", "wb") as f:
        f.write(logo_data)
    print("Saved debug_logo.png")
    
    logo = Image.open(io.BytesIO(logo_data))
    logo.load()
    print(f"Logo loaded successfully: {logo.size}, {logo.mode}")
except Exception as e:
    print(f"FAILED to load logo: {e}")

# 2. Try to load QR Code
try:
    print(f"Loading QR Code from {QR_PATH}...")
    if not os.path.exists(QR_PATH):
        print("QR Code file does NOT exist!")
    else:
        file_size = os.path.getsize(QR_PATH)
        print(f"File size: {file_size} bytes")
        qr = Image.open(QR_PATH)
        qr.load()
        print(f"QR Code loaded successfully: {qr.size}, {qr.mode}")
except Exception as e:
    print(f"FAILED to load QR Code: {e}")
